// Build one item per platform, carrying all context forward
const webhookData = $('Webhook').item.json.body;
const brandVoice = $('Fetch Brand Voice').item.json;
const systemPrompt = $('Fetch System Prompt').item.json.system_prompt;

const platforms = Array.isArray(webhookData.platforms) ? webhookData.platforms : [webhookData.platforms];

const platformConstraints = {
  linkedin:  { maxChars: 1300, format: 'professional long-form, can include line breaks and emojis, ideal for thought leadership' },
  x:         { maxChars: 280,  format: 'punchy single idea, optional hashtags at end, no fluff' },
  instagram: { maxChars: 2200, format: 'engaging storytelling with strong hook, heavy emoji use encouraged, hashtags at end' },
  facebook:  { maxChars: 500,  format: 'conversational, community-friendly, question or CTA at end' }
};

return platforms.map(platform => {
  const key = platform.toLowerCase();
  const constraints = platformConstraints[key] || { maxChars: 500, format: 'general social media post' };
  return {
    json: {
      platform: key,
      maxChars: constraints.maxChars,
      format: constraints.format,
      topic: webhookData.topic,
      tone: webhookData.tone,
      include_hashtags: webhookData.include_hashtags,
      user_id: webhookData.user_id,
      brand_voice: brandVoice.brand_voice,
      niche: brandVoice.niche,
      writing_style: brandVoice.writing_style,
      system_prompt: systemPrompt
    }
  };
});

