const raw = $input.item.json;
const inputData = $('Split by Platform').item.json;

// Extract text content from Claude response
let contentText = '';
if (raw.content && Array.isArray(raw.content)) {
  contentText = raw.content
    .filter(block => block.type === 'text')
    .map(block => block.text)
    .join('');
} else {
  throw new Error('Unexpected Claude response shape: ' + JSON.stringify(raw));
}

// Strip markdown fences if present
const cleaned = contentText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse Claude JSON: ' + e.message + '\nRaw: ' + cleaned.substring(0, 300));
}

const required = ['post_text', 'hashtags', 'suggested_image_prompt'];
for (const key of required) {
  if (!(key in parsed)) {
    throw new Error(`Missing required key in Claude response: ${key}`);
  }
}

// Enforce char limit — hard truncate as safety net
if (parsed.post_text.length > inputData.maxChars) {
  parsed.post_text = parsed.post_text.substring(0, inputData.maxChars - 3) + '...';
}

return {
  json: {
    platform: inputData.platform,
    user_id: inputData.user_id,
    post_text: parsed.post_text,
    hashtags: parsed.hashtags,
    suggested_image_prompt: parsed.suggested_image_prompt,
    char_count: parsed.post_text.length
  }
};

// Collect all platform results and merge into a single response
const allItems = $input.all();

const posts = allItems.map(item => ({
  platform: item.json['Parse Claude Response_platform'] || item.json.platform,
  post_text: item.json['Parse Claude Response_post_text'] || item.json.post_text,
  hashtags: item.json['Parse Claude Response_hashtags'] || item.json.hashtags,
  suggested_image_prompt: item.json['Parse Claude Response_suggested_image_prompt'] || item.json.suggested_image_prompt,
  char_count: item.json['Parse Claude Response_char_count'] || item.json.char_count,
  content_id: item.json['Insert Content Output_id'] || item.json.id
}));

return [
  {
    json: {
      success: true,
      total_platforms: posts.length,
      total_credits_used: posts.length * 5,
      posts
    }
  }
];
